1. Claude proxy code ready for deployment

This is the smallest useful shape:

your app points Anthropic traffic to DarkMatter

DarkMatter forwards to Anthropic

DarkMatter records request + response as verifiable steps

the proxy does not block Claude if recording fails unless you choose strict mode

Environment variables
Bash
ANTHROPIC_API_KEY=sk-ant-...
DARKMATTER_INTERNAL_SIGNING_KEY=...
DARKMATTER_BASE_URL=https://darkmatterhub.ai
STRICT_RECORDING=false
Server route design

Use these routes:

POST /proxy/anthropic/v1/sessions
POST /proxy/anthropic/v1/sessions/:sessionId/events
GET  /proxy/anthropic/health
Core proxy helpers
JavaScript
// src/claude_proxy.js
'use strict';

const crypto = require('crypto');

const ANTHROPIC_BASE = 'https://api.anthropic.com';

function nowIso() {
  return new Date().toISOString();
}

function pickHeaders(reqHeaders = {}) {
  const out = {};
  const allowed = [
    'anthropic-version',
    'anthropic-beta',
    'content-type',
    'x-api-key',
    'authorization'
  ];
  for (const k of allowed) {
    const v = reqHeaders[k] || reqHeaders[k.toLowerCase()];
    if (v) out[k] = v;
  }
  return out;
}

function redactHeaders(headers = {}) {
  const out = { ...headers };
  if (out['x-api-key']) out['x-api-key'] = 'REDACTED';
  if (out['authorization']) out['authorization'] = 'REDACTED';
  return out;
}

function shortId(prefix = 'evt') {
  return `${prefix}_${crypto.randomBytes(8).toString('hex')}`;
}

async function forwardToAnthropic(path, method, headers, body) {
  const res = await fetch(`${ANTHROPIC_BASE}${path}`, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });

  const text = await res.text();
  let json = null;
  try {
    json = JSON.parse(text);
  } catch {
    json = { raw_text: text };
  }

  return {
    ok: res.ok,
    status: res.status,
    headers: Object.fromEntries(res.headers.entries()),
    body: json,
  };
}

async function recordStep(dm, step) {
  return dm.commit(step);
}

function buildRequestStep({ workspaceId, source, sessionId, routePath, requestBody, requestHeaders, parentId }) {
  return {
    workspace_id: workspaceId,
    source,
    provider: 'anthropic',
    session_id: sessionId || null,
    step_type: 'request',
    route_path: routePath,
    client_timestamp: nowIso(),
    payload: {
      request: requestBody,
      request_headers: redactHeaders(requestHeaders),
    },
    parent_id: parentId || null,
  };
}

function buildResponseStep({ workspaceId, source, sessionId, routePath, response, parentId }) {
  return {
    workspace_id: workspaceId,
    source,
    provider: 'anthropic',
    session_id: sessionId || null,
    step_type: 'response',
    route_path: routePath,
    client_timestamp: nowIso(),
    payload: {
      status: response.status,
      body: response.body,
    },
    parent_id: parentId || null,
  };
}

module.exports = {
  pickHeaders,
  forwardToAnthropic,
  recordStep,
  buildRequestStep,
  buildResponseStep,
  shortId,
};
Express routes

This assumes you already have a dm.commit() server-side wrapper and auth middleware that resolves workspace/user.

JavaScript
// in src/server.js
const {
  pickHeaders,
  forwardToAnthropic,
  recordStep,
  buildRequestStep,
  buildResponseStep,
  shortId,
} = require('./claude_proxy');

function shouldFailClosed() {
  return String(process.env.STRICT_RECORDING).toLowerCase() === 'true';
}

app.get('/proxy/anthropic/health', (_req, res) => {
  res.json({ ok: true, provider: 'anthropic' });
});

app.post('/proxy/anthropic/v1/sessions', requireAuth, async (req, res) => {
  const workspaceId = req.workspace?.id || null;
  const source = 'claude_managed_agents_proxy';
  const routePath = '/v1/sessions';
  const upstreamHeaders = pickHeaders(req.headers);

  let requestCommit = null;

  try {
    requestCommit = await recordStep(dm, buildRequestStep({
      workspaceId,
      source,
      sessionId: null,
      routePath,
      requestBody: req.body,
      requestHeaders: upstreamHeaders,
      parentId: null,
    }));
  } catch (err) {
    console.error('record request failed', err);
    if (shouldFailClosed()) {
      return res.status(503).json({ error: 'recording_failed' });
    }
  }

  try {
    const upstream = await forwardToAnthropic(routePath, 'POST', upstreamHeaders, req.body);

    let sessionId = upstream.body?.id || upstream.body?.session_id || null;

    try {
      await recordStep(dm, buildResponseStep({
        workspaceId,
        source,
        sessionId,
        routePath,
        response: upstream,
        parentId: requestCommit?.id || null,
      }));
    } catch (err) {
      console.error('record response failed', err);
      if (shouldFailClosed()) {
        return res.status(503).json({ error: 'recording_failed_after_forward' });
      }
    }

    return res.status(upstream.status).json(upstream.body);
  } catch (err) {
    console.error('anthropic upstream failed', err);
    return res.status(502).json({ error: 'upstream_failed' });
  }
});

app.post('/proxy/anthropic/v1/sessions/:sessionId/events', requireAuth, async (req, res) => {
  const workspaceId = req.workspace?.id || null;
  const source = 'claude_managed_agents_proxy';
  const sessionId = req.params.sessionId;
  const routePath = `/v1/sessions/${sessionId}/events`;
  const upstreamHeaders = pickHeaders(req.headers);

  let requestCommit = null;

  try {
    requestCommit = await recordStep(dm, buildRequestStep({
      workspaceId,
      source,
      sessionId,
      routePath,
      requestBody: req.body,
      requestHeaders: upstreamHeaders,
      parentId: null,
    }));
  } catch (err) {
    console.error('record event request failed', err);
    if (shouldFailClosed()) {
      return res.status(503).json({ error: 'recording_failed' });
    }
  }

  try {
    const upstream = await forwardToAnthropic(routePath, 'POST', upstreamHeaders, req.body);

    try {
      await recordStep(dm, buildResponseStep({
        workspaceId,
        source,
        sessionId,
        routePath,
        response: upstream,
        parentId: requestCommit?.id || null,
      }));
    } catch (err) {
      console.error('record event response failed', err);
      if (shouldFailClosed()) {
        return res.status(503).json({ error: 'recording_failed_after_forward' });
      }
    }

    return res.status(upstream.status).json(upstream.body);
  } catch (err) {
    console.error('anthropic upstream failed', err);
    return res.status(502).json({ error: 'upstream_failed' });
  }
});
Better step modeling

Once this basic proxy works, split request events more cleanly:

session_created

user_event_submitted

tool_event_recorded

model_response_received

That will make reconstruction much better than generic request/response pairs.

Optional: deterministic parent linkage

Use per-session tip lookup so steps chain properly:

JavaScript
async function getSessionTip(sessionId) {
  // query latest commit for this session
}

async function commitForSession(sessionId, step) {
  const parent = await getSessionTip(sessionId);
  return dm.commit({ ...step, parent_id: parent?.id || null });
}

That is worth adding as soon as the basic proxy is live.

2. Full dashboard HTML/CSS spec aligned to Claude Console feel

Do not clone Claude. Borrow the layout rhythm.

Layout
┌────────────────────────────────────────────────────────────┐
│ Top nav                                                    │
├───────────────┬───────────────────────────────┬────────────┤
│ Left rail     │ Main record panel             │ Right rail │
│ records       │ record / timeline / raw       │ verify     │
└───────────────┴───────────────────────────────┴────────────┘
Visual principles

light shell

white cards

soft gray surfaces

dark ink

mono only for identifiers, timestamps, hashes, tabs

no provider-themed colors

green only for integrity success, used sparingly

