  font-size: 12px;
  color: var(--muted);
}

.dm-sidebar-footer {
  border-top: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.dm-main {
  min-width: 0;
  min-height: 0;
  display: flex;
  flex-direction: column;
  padding: 20px;
  gap: 16px;
}

.dm-record-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 20px;
}

.dm-record-heading h1 {
  margin: 0 0 8px 0;
  font-size: 28px;
  line-height: 1.1;
  letter-spacing: -0.03em;
}

.dm-record-submeta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px 12px;
  color: var(--muted);
  font-size: 13px;
}

.dm-status-ok {
  color: #067647;
  background: var(--green-bg);
  border: 1px solid var(--green-border);
  border-radius: 999px;
  padding: 2px 10px;
  font-weight: 600;
}

.dm-record-actions {
  display: flex;
  gap: 8px;
}

.dm-tabs {
  display: flex;
  gap: 8px;
}

.dm-tabpanel {
  flex: 1;
  min-height: 0;
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.dm-entry {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 14px 16px;
  box-shadow: var(--shadow);
}

.dm-entry-user {
  background: var(--ink);
  color: white;
  border-color: var(--ink);
}

.dm-entry-agent {
  background: var(--surface);
}

.dm-entry-label {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  margin-bottom: 8px;
  color: inherit;
  opacity: 0.8;
}

.dm-entry-body {
  font-size: 15px;
  line-height: 1.6;
}

.dm-entry-time {
  margin-top: 10px;
  font-size: 12px;
  opacity: 0.75;
}

.dm-proof-header {
  font-size: 14px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-bottom: 16px;
}

.dm-proof-checks {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.dm-proof-check {
  border: 1px solid var(--border);
  border-radius: 10px;
  background: var(--surface-2);
  padding: 12px 14px;
  font-size: 14px;
}

.dm-proof-check.ok::before {
  content: "✓ ";
  color: var(--green);
  font-weight: 700;
}

.dm-proof-summary {
  margin-top: 16px;
  padding: 14px;
  border-radius: 10px;
  background: var(--green-bg);
  border: 1px solid var(--green-border);
  color: #067647;
  font-weight: 600;
}

.dm-proof-actions {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 16px;
}
